mapper.select:
/* CustMngMapper.custMngList */ SELECT A.PRMT_ID , E.PRMT_NM , A.CONTRACT_NUM , A.SUB_LINK_NAME /* 고객명 */ , A.SUBSCRIBER_NO /* 전화번호 */ , A.MNG_NM /* 받는분이름 */ , A.MNG_NM AS MASK_MNG_NM /* 받는분이름 */ , A.TEL_FN1 , A.TEL_MN1 , A.TEL_RN1 , A.TEL_FN1 || '-' || TEL_MN1 || '-' || TEL_RN1 AS TEL1 , A.TEL_FN2 , A.TEL_MN2 , A.TEL_RN2 , A.TEL_FN2 || '-' || TEL_MN2 || '-' || TEL_RN2 AS TEL2 , A.POST , A.ADDR , A.ADDR_BJD , A.ADDR_DTL , A.ADDR_DTL AS MASK_ADDR_DTL
, D.PRDT_NM || CASE WHEN (C.CNT = 1 OR C.CNT IS NULL) THEN '' ELSE '(외)' END AS PRDT_NM , (SELECT SUM(RE.QUANTITY) FROM MSP_GIFT_PRDT PR ,MSP_GIFT_PRMT_RESULT RE WHERE RE.CONTRACT_NUM = A.CONTRACT_NUM AND RE.PRMT_ID = A.PRMT_ID AND PR.PRDT_ID = RE.PRDT_ID ) QUANTITY
, (SELECT SUM(RE.QUANTITY * PR.OUT_UNIT_PRIC) FROM MSP_GIFT_PRDT PR ,MSP_GIFT_PRMT_RESULT RE WHERE RE.CONTRACT_NUM = A.CONTRACT_NUM AND RE.PRMT_ID = A.PRMT_ID AND PR.PRDT_ID = RE.PRDT_ID ) SUM_AMOUNT
, E.AMOUNT_LIMIT /* 제한금액 */
, TO_CHAR(TO_DATE(B.REQ_IN_DAY,'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') REQ_IN_DAY /* 신청일 */
, SUB.LST_COM_ACTV_DATE /* 개통일 */
, A.GIFT_REGST_DATE /* 사은품 신청일 */
, B.FST_RATE_CD /* 고객 최초 요금제 */ , B.FST_RATE_NM /* 고객 최초 요금제명 */
, B.LST_RATE_NM /* 현재요금제명 */
, A.SMS_SEND_DATE /* 문자 전송일 */
, A.REGST_ID , A.REGST_DTTM , A.RVISN_ID , A.RVISN_DTTM , E.PRMT_TYPE , FN_GET_CODENM('ORG1010', E.PRMT_TYPE) AS PRMT_TYPE_NM , E.CHOICE_LIMIT , FN_GET_ORGNM(SUB.OPEN_AGNT_CD) AS OPEN_AGNT_NM , FN_GET_ORGNM(PUM.ORGN_ID) AS FST_USIM_ORG_NM , (SELECT MAX(TO_CHAR(TO_DATE(EFFECTIVE_DATE,'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS')) FROM MSP_JUO_FEATURE_INFO WHERE SERVICE_TYPE = 'P' AND SOC = B.LST_RATE_CD AND CONTRACT_NUM = A.CONTRACT_NUM) AS LST_RATE_DT , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'MSP0003' AND CD_VAL = SUB.SUB_STATUS) AS SUB_STATUS_NM , E.SHOW_YN AS SHOW_YN , DECODE(E.SHOW_YN,'N','비노출','노출') AS SHOW_YN_NM , TO_CHAR(TO_DATE(E.BILL_DT, 'YYYYMMDD'),'YYYY-MM-DD') AS BILL_DT , E.ORGN_ID AS PRMT_ORGN_ID , FN_GET_ORGNM(E.ORGN_ID) AS PRMT_ORGN_NM FROM MSP_GIFT_PRMT_CUSTOMER A ,MSP_REQUEST_DTL B ,(SELECT CONTRACT_NUM , PRMT_ID , COUNT(*) CNT , MIN(PRDT_ID) PRDT_ID FROM MSP_GIFT_PRMT_RESULT GROUP BY CONTRACT_NUM ,PRMT_ID ) C ,MSP_GIFT_PRDT D ,MSP_GIFT_PRMT E ,MSP_JUO_SUB_INFO SUB ,MSP_PARTNER_USIM_MST PUM WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM(+) AND A.PRMT_ID = C.PRMT_ID(+) AND D.PRDT_ID(+) = C.PRDT_ID AND D.USE_YN(+) = 'Y' AND A.PRMT_ID = E.PRMT_ID AND A.CONTRACT_NUM = SUB.CONTRACT_NUM AND B.FST_USIM_NO = PUM.USIM_NO(+)
AND B.REQ_IN_DAY BETWEEN #{frDate, jdbcType=VARCHAR}||'000000' AND #{toDate, jdbcType=VARCHAR}||'235959'
AND E.PRMT_NM LIKE '%' || #{searchTxt, jdbcType=VARCHAR} || '%'
AND E.PRMT_ID = #{searchTxt, jdbcType=VARCHAR}
AND D.PRDT_NM LIKE '%' || #{searchTxt, jdbcType=VARCHAR} || '%'
AND D.PRDT_ID = #{searchTxt, jdbcType=VARCHAR}
AND A.CONTRACT_NUM = #{searchTxt, jdbcType=VARCHAR}
AND A.SUB_LINK_NAME LIKE '%' || #{searchTxt, jdbcType=VARCHAR} || '%'
AND A.SUBSCRIBER_NO = #{searchTxt, jdbcType=VARCHAR}
AND E.ORGN_ID = #{prmtOrgnId}
AND SUBSTR(E.BILL_DT, 1, 6) = #{billDt}
AND E.SHOW_YN = #{showYn}
ORDER BY 1,3

mapper.update:
/* CustMngMapper.giftPrmtCustomerUpdate */
UPDATE  MSP_GIFT_PRMT_CUSTOMER
   SET  SMS_SEND_DATE = #{smsSendDate, jdbcType=VARCHAR}
      , GIFT_REGST_DATE = TO_CHAR(SYSDATE,'YYYYMMDD')
      , MNG_NM = #{mngNm, jdbcType=VARCHAR}

	  , TEL_FN1 = #{telFn1, jdbcType=VARCHAR}
	  , TEL_MN1 = #{telMn1, jdbcType=VARCHAR}
	  , TEL_RN1 = #{telRn1, jdbcType=VARCHAR}
	  , TEL_FN2 = #{telFn2, jdbcType=VARCHAR}
	  , TEL_MN2 = #{telMn2, jdbcType=VARCHAR}
	  , TEL_RN2 = #{telRn2, jdbcType=VARCHAR}

      , POST = #{post, jdbcType=VARCHAR}
      , ADDR = #{addr, jdbcType=VARCHAR}
      , ADDR_BJD = #{addrBjd, jdbcType=VARCHAR}
      , ADDR_DTL = #{addrDtl, jdbcType=VARCHAR}

      , RVISN_ID = #{sessionUserId, jdbcType=VARCHAR}
      , RVISN_DTTM = SYSDATE

 WHERE  PRMT_ID = #{prmtId, jdbcType=VARCHAR}
 AND    CONTRACT_NUM = #{contractNum, jdbcType=VARCHAR}

mapper.delete:
/* CustMngMapper.giftPrmtResultDelete */
DELETE  MSP_GIFT_PRMT_RESULT
 WHERE  PRMT_ID = #{prmtId, jdbcType=VARCHAR}
 AND    CONTRACT_NUM = #{contractNum, jdbcType=VARCHAR}

